const { ethers } = require("ethers");
require("dotenv").config();

// XCM Message generated by calc_xcm_message.js
const XCM_MESSAGE_HEX = "";

// CORRECT XCM Precompile address on Asset Hub (from docs)
const XCM_PRECOMPILE = "0x00000000000000000000000000000000000a0000";

// Asset Hub RPC
const ASSET_HUB_RPC = "https://eth-rpc.polkadot.io/";

async function main() {
    console.log("=== XCM Precompile Test (Correct Address) ===\n");

    const provider = new ethers.JsonRpcProvider(ASSET_HUB_RPC);

    // Check if precompile exists
    console.log("Precompile Address:", XCM_PRECOMPILE);
    const code = await provider.getCode(XCM_PRECOMPILE);
    console.log("Has code:", code && code !== "0x" ? "YES" : "Precompile (no bytecode expected)");

    // Interface based on docs
    // weighMessage: (bytes message) -> (Weight)
    // execute: (bytes message, Weight weight) -> ()
    // Weight is a struct { uint64 refTime, uint64 proofSize }

    const iface = new ethers.Interface([
        // weighMessage returns a Weight struct
        "function weighMessage(bytes calldata message) external view returns (tuple(uint64 refTime, uint64 proofSize))",
        // execute takes message first, then weight tuple
        "function execute(bytes calldata message, tuple(uint64 refTime, uint64 proofSize) weight) external"
    ]);

    // Test 1: weighMessage
    console.log("\n--- Test 1: weighMessage ---");
    try {
        const weighData = iface.encodeFunctionData("weighMessage", [XCM_MESSAGE_HEX]);
        console.log("weighMessage selector:", weighData.slice(0, 10));

        const result = await provider.call({
            to: XCM_PRECOMPILE,
            data: weighData
        });

        console.log("Raw result:", result);

        if (result && result !== "0x") {
            const decoded = iface.decodeFunctionResult("weighMessage", result);
            console.log("✅ weighMessage SUCCESS!");
            console.log("   RefTime:", decoded[0].refTime.toString());
            console.log("   ProofSize:", decoded[0].proofSize.toString());
        } else {
            console.log("❌ Empty result");
        }
    } catch (e) {
        console.log("❌ Error:", e.message);
        if (e.data) console.log("   Data:", e.data);
    }

    // Test 2: execute dry-run
    console.log("\n--- Test 2: execute (dry-run) ---");
    try {
        const wallet = new ethers.Wallet(process.env.ASSET_PK, provider);

        // Use generous weight
        const weight = { refTime: 10000000000n, proofSize: 500000n };

        const executeData = iface.encodeFunctionData("execute", [XCM_MESSAGE_HEX, weight]);
        console.log("execute selector:", executeData.slice(0, 10));

        const result = await wallet.call({
            to: XCM_PRECOMPILE,
            data: executeData
        });

        console.log("✅ execute dry-run result:", result || "(empty = success)");
    } catch (e) {
        console.log("❌ execute dry-run error:", e.message);
        if (e.data) console.log("   Revert data:", e.data);
    }

    console.log("\n=== Test Complete ===");
}

main().catch(console.error);
